#include "SYsULexer.h" // 确保这里的头文件名与您生成的词法分析器匹配
#include <fstream>
#include <iostream>
#include <unordered_map>

// 映射定义，将ANTLR的tokenTypeName映射到clang的格式
std::unordered_map<std::string, std::string> tokenTypeMapping = {
  { "Int", "int" },
  { "Identifier", "identifier" },
  { "LeftParen", "l_paren" },
  { "RightParen", "r_paren" },
  { "RightBrace", "r_brace" },
  { "LeftBrace", "l_brace" },
  { "LeftBracket", "l_square" },
  { "RightBracket", "r_square" },
  { "Constant", "numeric_constant" },
  { "Return", "return" },
  { "Semi", "semi" },
  { "EOF", "eof" },
  { "Equal", "equal" },
  { "Plus", "plus" },
  { "Comma", "comma" },

  // 在这里继续添加其他映射
};

void
print_token(const antlr4::Token* token,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer)
{
  // Cast to our custom token type
  auto positionedToken = dynamic_cast<const SYsULexer::PositionedToken*>(token);
  if (!positionedToken) {
    // Fallback to default formatting
    outFile << token->toString() << std::endl;
    return;
  }

  // Get token name
  std::string tokenName;
  if (token->getType() == antlr4::Token::EOF) {
    tokenName = "eof";
  } else {
    tokenName = lexer.getVocabulary().getSymbolicName(token->getType());
    if (tokenName.empty()) {
      tokenName = std::to_string(token->getType());
    }
  }

  // Format token as required
  outFile << tokenName << " '" << token->getText() << "'";
  if (positionedToken->startOfLine) outFile << " [StartOfLine]";
  if (positionedToken->leadingSpace) outFile << " [LeadingSpace]";
  outFile << " Loc=<" << positionedToken->filename 
          << ":" << token->getLine() 
          << ":" << positionedToken->col << ">" << std::endl;
}

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::cout << "程序 '" << argv[0] << std::endl;
  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  antlr4::ANTLRInputStream input(inFile);
  SYsULexer lexer(&input);

  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  for (auto&& token : tokens.getTokens()) {
    print_token(token, tokens, outFile, lexer);
  }
}

